import { Component, Prop, h, Element, Host, Event, EventEmitter } from '@stencil/core';

@Component({
  tag: 'wdpr-tab',
  styleUrl: 'wdpr-tab.css',
  scoped: true,
})
export class WdprTab {
  @Element() el: HTMLElement;

  /**
   * Tab id
   * @type {string}
   */
  @Prop() tabId: string;

  /**
   * Tab label
   * @type {string}
   */
  @Prop() label: string;

  /**
   * Tab secondary label
   * @type {string}
   */
  @Prop() secondaryLabel: string;

  /**
   * Tab icon
   * @type {string}
   */
  @Prop() icon: string;

  /**
   * if `true`, the tab is currently active.
   * @type {boolean}
   */
  @Prop({ reflect: true, mutable: true }) active: boolean = false;

  /**
   * if `true`, the tab is disabled
   * @type {boolean}
   */
  @Prop({ reflect: true, mutable: true }) disabled: boolean = false;

  /**
   * if `true`, the tab will grow to fill the available space.
   * @type {boolean}
   */
  @Prop({ reflect: true, mutable: true }) grow: boolean = false;

  /**
   * The id of the element that this tab controls
   * @type {string}
   */
  @Prop() controlsId: string;

  /**
   * The tabindex of the tab
   * @type {number}
   */
  @Prop() customTabIndex: number;

  @Prop({ reflect: true }) showInactiveBorderBottom: boolean = true;

  /**
   * Emitted when the tab button is clicked.
   * This is used by the parent wdpr-tab-bar to manage the active state.
   */
  @Event() tabClicked: EventEmitter<{ tabElement: unknown }>;

  private _handleClick = (): void => {
    if (this.disabled) return;

    this.tabClicked.emit({ tabElement: this.el });
  };

  render() {
    return (
      <Host
        id={this.tabId}
        role="tab"
        class="tab-button"
        aria-selected={this.active.toString()}
        aria-controls={this.controlsId}
        aria-disabled={this.disabled ? 'true' : undefined}
        tabindex={this.disabled ? -1 : (this.customTabIndex ?? 0)}
        onClick={this._handleClick}
        disabled={this.disabled}
      >
        <div class="tab-content">
          <div class="tab-icon-wrapper">
            {this.icon && <wdpr-icon-library icon={this.icon} size="small" decorative={true}></wdpr-icon-library>}

            {this.secondaryLabel && !this.icon && <span class="secondary-label">{this.secondaryLabel}</span>}
          </div>

          <span class="main-label">{this.label}</span>
        </div>
      </Host>
    );
  }
}
